"""Run STL validation on all supplier files using the improved validator logic."""
import json
import math
import os
import glob


def _cross(a, b):
    return (
        a[1] * b[2] - a[2] * b[1],
        a[2] * b[0] - a[0] * b[2],
        a[0] * b[1] - a[1] * b[0],
    )


def _sub(a, b):
    return (a[0] - b[0], a[1] - b[1], a[2] - b[2])


def _dot(a, b):
    return a[0] * b[0] + a[1] * b[1] + a[2] * b[2]


def _magnitude(v):
    return math.sqrt(v[0] ** 2 + v[1] ** 2 + v[2] ** 2)


def _normalize(v):
    m = _magnitude(v)
    if m < 1e-12:
        return (0.0, 0.0, 0.0)
    return (v[0] / m, v[1] / m, v[2] / m)


def _triangle_area(v1, v2, v3):
    return 0.5 * _magnitude(_cross(_sub(v2, v1), _sub(v3, v1)))


def parse_stl(path: str) -> dict:
    issues = []
    issue_types = set()
    triangles = []  # list of (declared_normal, [v1, v2, v3])

    with open(path, "r", errors="replace") as fh:
        lines = fh.readlines()

    i = 0
    while i < len(lines):
        line = lines[i].strip()

        if line.startswith("facet normal"):
            parts = line.split()
            try:
                declared_normal = (float(parts[2]), float(parts[3]), float(parts[4]))
            except (IndexError, ValueError):
                issues.append(f"Malformed facet normal at line {i + 1}")
                issue_types.add("malformed")
                i += 1
                continue

            vertices = []
            i += 1
            if i < len(lines) and lines[i].strip() == "outer loop":
                i += 1
                for _ in range(3):
                    if i < len(lines):
                        vline = lines[i].strip()
                        if vline.startswith("vertex"):
                            vparts = vline.split()
                            try:
                                vertices.append(
                                    (float(vparts[1]), float(vparts[2]), float(vparts[3]))
                                )
                            except (IndexError, ValueError):
                                issues.append(f"Malformed vertex at line {i + 1}")
                                issue_types.add("malformed")
                        i += 1

            if len(vertices) == 3:
                triangles.append((declared_normal, vertices))
            else:
                issues.append(f"Incomplete triangle near line {i + 1}")
                issue_types.add("malformed")
            continue

        i += 1

    if not triangles:
        issues.append("No valid faces found")
        issue_types.add("no_faces")

    # --- Manifold check: every edge must be shared by exactly 2 triangles ---
    edge_count: dict = {}
    for _, verts in triangles:
        rounded = [tuple(round(x, 6) for x in v) for v in verts]
        for j in range(3):
            edge = tuple(sorted([rounded[j], rounded[(j + 1) % 3]]))
            edge_count[edge] = edge_count.get(edge, 0) + 1

    open_edges = sum(1 for cnt in edge_count.values() if cnt == 1)
    if open_edges > 0:
        issues.append(f"Mesh has {open_edges} open edge(s) - not a closed solid")
        issue_types.add("open_edges")

    # --- Degenerate triangle check ---
    degenerate_count = 0
    for _, verts in triangles:
        area = _triangle_area(*verts)
        if area < 1e-12:
            degenerate_count += 1
    if degenerate_count > 0:
        issues.append(f"Mesh has {degenerate_count} degenerate (zero-area) triangle(s)")
        issue_types.add("degenerate_triangles")

    # --- Normal consistency check (winding order) ---
    inverted_count = 0
    for declared_normal, verts in triangles:
        computed = _cross(_sub(verts[1], verts[0]), _sub(verts[2], verts[0]))
        computed_mag = _magnitude(computed)
        if computed_mag < 1e-12:
            continue  # degenerate, already flagged
        computed_norm = _normalize(computed)
        declared_mag = _magnitude(declared_normal)
        if declared_mag < 1e-12:
            continue  # zero declared normal, skip
        declared_norm = _normalize(declared_normal)
        dot = _dot(computed_norm, declared_norm)
        if dot < 0.0:  # normal points opposite direction
            inverted_count += 1

    if inverted_count > 0:
        issues.append(f"Mesh has {inverted_count} inverted normal(s)")
        issue_types.add("inverted_normals")

    surface_area = sum(_triangle_area(*verts) for _, verts in triangles)

    return {
        "valid": len(issues) == 0,
        "triangle_count": len(triangles),
        "surface_area": round(surface_area, 6),
        "issues": issues,
        "issue_types": list(issue_types),
    }


def classify_reason(issue_types):
    """Return the primary reason string for a failed file."""
    # Priority order
    if "inverted_normals" in issue_types:
        return "inverted_normals"
    if "open_edges" in issue_types:
        return "open_edges"
    if "degenerate_triangles" in issue_types:
        return "degenerate_triangles"
    if "no_faces" in issue_types:
        return "no_faces"
    if "malformed" in issue_types:
        return "malformed"
    return "unknown"


def main():
    files = sorted(glob.glob("supplier_*.stl"))
    results = []

    for stl_file in files:
        result = parse_stl(stl_file)
        entry = {"file": stl_file, "valid": result["valid"]}
        if not result["valid"]:
            # Combine all issue types for compound failures
            issue_types = result["issue_types"]
            if len(issue_types) > 1:
                entry["reason"] = ", ".join(sorted(issue_types))
            else:
                entry["reason"] = classify_reason(issue_types)
        results.append(entry)
        status = "PASS" if result["valid"] else f"FAIL ({entry.get('reason', '')})"
        print(f"{stl_file}: {status}")
        if result["issues"]:
            for issue in result["issues"]:
                print(f"  - {issue}")

    report = {"results": results}
    with open("validation_report.json", "w") as f:
        json.dump(report, f, indent=2)

    print(f"\nReport written to validation_report.json")
    valid_count = sum(1 for r in results if r["valid"])
    print(f"Valid: {valid_count}/{len(results)}")


if __name__ == "__main__":
    main()

